const realizarVenta = async () => {
  try {
    // 1️⃣ Validar campos del cliente
    if (!clienteNombre.trim() || !clienteApellido.trim()) {
      setMensaje("⚠️ Ingresa nombre y apellido del cliente.");
      return;
    }

    // 2️⃣ Validar que haya productos en el carrito
    if (carrito.length === 0) {
      setMensaje("⚠️ Agrega al menos un producto al carrito.");
      return;
    }

    // 3️⃣ Buscar cliente existente
    let cliente = clientes.find(
      (c) =>
        (c.Nombre || c.nombre || "").toLowerCase() === clienteNombre.toLowerCase() &&
        (c.Apellido || c.apellido || "").toLowerCase() === clienteApellido.toLowerCase()
    );

    // 4️⃣ Crear cliente automáticamente si no existe
    if (!cliente) {
      const resCliente = await axios.post("http://localhost:5000/api/clientes", {
        Nombre: clienteNombre,
        Apellido: clienteApellido,
        Telefono: clienteTelefono || "",
      });

      if (!resCliente.data || (!resCliente.data.ClienteID && !resCliente.data.id)) {
        setMensaje("❌ Error al crear el cliente.");
        return;
      }

      cliente = resCliente.data;
      setClientes([...clientes, cliente]);
      setMensaje(`✅ Cliente "${clienteNombre} ${clienteApellido}" agregado.`);
    }

    // 5️⃣ Registrar venta
    const resVenta = await axios.post("http://localhost:5000/api/ventas", {
      ClienteID: cliente.ClienteID || cliente.id,
      productos: carrito,
      EmisorNombre: "Mi Negocio",
    });

    if (!resVenta.data || !resVenta.data.VentaID) {
      setMensaje("❌ Error al registrar la venta.");
      return;
    }

    // 6️⃣ Generar ticket
    setTicket({
      ...resVenta.data,
      NombreCliente: `${clienteNombre} ${clienteApellido}`,
    });

    // 7️⃣ Limpiar formulario y carrito
    setMensaje("✅ Venta realizada correctamente.");
    setCarrito([]);
    setClienteNombre("");
    setClienteApellido("");
    setClienteTelefono("");

    // 8️⃣ Recargar productos (por si cambió stock)
    await obtenerProductos();

  } catch (err) {
    console.error("Error en realizarVenta:", err);
    setMensaje("❌ Error al procesar la venta.");
  }
};
